behavior.onMouseDown:
const switchBody = context.getCellByPosition(1, 0);
if (switchBody && !switchBody.isOn) {
  context.updateCellProperty(1, 0, { isOn: true, isPowered: true });
}

behavior.onMouseUp:
const switchBody = context.getCellByPosition(1, 0);
if (switchBody?.isOn) {
  context.updateCellProperty(1, 0, { isOn: false, isPowered: false });
}
